          import sailpoint.object.Identity;
          import sailpoint.tools.Util;        
					
          String values = "";
          try{
          if(null != form.getField("firstname") && null != form.getField("firstname").getValue() && Util.isNullOrEmpty(identityModel.get("reenableContractorName"))){
          values = form.getField("firstname").getValue();
          }
          else if ( Util.isNotNullOrEmpty(identityModel.get("reenableContractorName") ) && (null == identityModel.get("creationCheckbox") || !identityModel.get("creationCheckbox"))){
          Identity identity = context.getObjectByName(Identity.class, identityModel.get("reenableContractorName"));
          if (identity != null){
         		  userMap.putAll(identity.getAttributes().getMap());
           		values = userMap.get("firstname");
          }
          }
          }catch(Exception e){
          	throw new RuntimeException("ERROR: In Field FirstName"+e,e);
          }

          return values;

