          if(null != form.getField("ctrexpDt") && null != form.getField("ctrexpDt").getValue()){
          dateFormat = form.getField("ctrexpDt").getValue();
          }
          else if( null != identityModel && (null == identityModel.get("creationCheckbox") || identityModel.get("creationCheckbox"))){
          dateFormat = today90;
          }
          else if( null != identityModel && Util.isNullOrEmpty(identityModel.get("reenableContractorName"))){
          date = today90;
          }
          else if ( Util.isNotNullOrEmpty(identityModel.get("reenableContractorName")) && (null == identityModel.get("creationCheckbox") || !identityModel.get("creationCheckbox"))){
            if (userMap.get("ctrexpDt") != null){
              dateFormat = convertStringToDate(userMap.get("ctrexpDt"));
