                  import sailpoint.tools.Util;
                  import sailpoint.object.Identity;

                  boolean rdOnly = false; 
                    try{
                      Identity launcherID = context.getObjectByName(Identity.class,launcher);
                      if ( null != launcherID && Util.isNotNullOrEmpty(launcherID.getStringAttribute("isContractorManager")) && launcherID.getStringAttribute("isContractorManager").equalsIgnoreCase("true")) {
                        rdOnly = true;
                      }
									}catch(Exception e){
          						throw new RuntimeException("ERROR: In Field Is Contract Manager Attribute Script "+e,e);
          				}
                  return rdOnly;

 
          import sailpoint.tools.Util;
          import sailpoint.object.Identity;
          import sailpoint.object.Form;

          boolean isContMgr= false;
          try{
          if(null != form.getField("isContractorManager") && null != (form.getField("isContractorManager").getValue()) && form.getField("isContractorManager").getValue()){
          isContMgr = form.getField("isContractorManager").getValue();
          }else if ( Util.isNotNullOrEmpty(identityModel.get("reenableContractorName")) && (null == identityModel.get("creationCheckbox") || !identityModel.get("creationCheckbox"))){
                Object conMan = userMap.get("isContractorManager");
          			if (conMan instanceof boolean) {
                   boolean contractorManager = (Boolean) conMan;
                    if(contractorManager){
          				   isContMgr = true;
          			    }
                 }else if(conMan instanceof String){
                      String contractorManager = conMan.toString();
                   		if(contractorManager != null @and contractorManager.equalsIgnoreCase("true")){
          				   		isContMgr = true;
          			      }
                }
          }
          }catch(Exception e){
          	throw new RuntimeException("ERROR: In Field Is Contract Manager "+e,e);
          }
          return isContMgr;

                  import sailpoint.object.Filter;
                  import sailpoint.object.Form;
                  import sailpoint.object.Field;
                  import sailpoint.object.Custom;
                  import sailpoint.object.Identity;
try{
                  Field field = form.getField("manager");



                  Filter filter = Filter.ignoreCase(Filter.eq("type","Employee"));
                  Filter filterManager = Filter.eq("managerStatus",true);
                  Filter inactiveFilter = Filter.eq("inactive",false);

                  Filter filter1 = Filter.and(filter,inactiveFilter);
                  Filter finalFilter = Filter.and(filter1,filterManager);

                  field.setFilterString(finalFilter.toString());  
                  }catch(Exception e){
          	throw new RuntimeException("ERROR: In set Manager Filter String  "+e,e);
          }

  
                  import sailpoint.tools.Util;
                  import sailpoint.object.Identity;

                  boolean returnValue = false; 
try{
                  Identity launcherID = context.getObjectByName(Identity.class,launcher);
                  if ( null != launcherID && Util.isNotNullOrEmpty(launcherID.getStringAttribute("isContractorManager")) && launcherID.getStringAttribute("isContractorManager").equalsIgnoreCase("true"))  {
                  returnValue = true;
                  if(null != launcherID.getManager().getName() && null != launcherID.getManager()){
                  form.getField("manager").setValue(launcherID.getManager().getName());
                  }
                  //comment decache //context.decache(launcherID);
                  }
                  }catch(Exception e){
          	throw new RuntimeException("ERROR: In Field Manager "+e,e);
          }
                  return returnValue;

                  import sailpoint.object.Filter;        
try{
                  Filter filterManager = Filter.eq("isContractorManager","true");
                  Filter inactiveFilter = Filter.eq("inactive",false);

                  Filter workgroupsFilter = Filter.like("workgroups.name","Trusted Requesters",Filter.MatchMode.START);
                  
				  Filter finalFilter = Filter.or(Filter.and(inactiveFilter,filterManager),workgroupsFilter);

                  field.setFilterString(finalFilter.toString());  
                  }catch(Exception e){
          	throw new RuntimeException("ERROR: In Set Contractor Manager Filter String "+e,e);
          }

  
                  import sailpoint.tools.Util;
                  import sailpoint.object.Identity;

                  boolean returnValue = false; 
                    try{
                  Identity launcherID = context.getObjectByName(Identity.class,launcher);
                  if ( null != launcherID && Util.isNotNullOrEmpty(launcherID.getStringAttribute("isContractorManager")) && launcherID.getStringAttribute("isContractorManager").equalsIgnoreCase("true"))  {
                  returnValue = true;
                  form.getField("contractorManager").setValue(launcherID.getName());
                  //comment decache //context.decache(launcherID);
                  }
                  }catch(Exception e){
          	throw new RuntimeException("ERROR: In Field Vendor Manager "+e,e);
          }
                  return returnValue;

